"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { BarChart3, ChevronLeft, ChevronRight, Download, Droplets, FileText, Filter, Fuel, Pencil, Plus, Receipt, Search, SlidersHorizontal, Trash2, Truck, Users, Wallet, X } from "lucide-react";
import { fleetoraApi } from "../lib/api";
import { supabase } from "../lib/supabase";

type Vehicle = { id: string; registration_number: string };
type Driver = { id: string; full_name: string; phone?: string | null; license_number?: string | null; license_expiry?: string | null; status: string };
type Customer = { id: string; name: string; phone?: string | null; contact_name?: string | null; email?: string | null; credit_limit?: number; payment_terms_days?: number; status: string };
type Resources = { vehicles: Vehicle[]; drivers: Driver[]; customers: Customer[] };
type Trip = { id: string; trip_number: string; customer_id: string | null; vehicle_id: string | null; driver_id: string | null; origin: string; destination: string; material_name: string | null; status: string; rate_type: string; rate: number; quantity_tonnes: number; distance_km: number; empty_distance_km: number; freight_amount: number; scheduled_start_at: string | null; created_at: string; customer_name?: string | null; vehicle_registration?: string | null; driver_name?: string | null; customers?: { name: string } | null; vehicles?: { registration_number: string } | null; drivers?: { full_name: string } | null };
type PaginatedTrips = { data: Trip[]; pagination: { page: number; pageSize: number; total: number; totalPages: number } };
type TripFilters = { status: string; vehicleId: string; driverId: string; customerId: string; material: string; paymentStatus: string; dateFrom: string; dateTo: string; sort: string };
type FuelEntry = { id: string; vehicle_id: string | null; trip_id: string | null; filled_at: string; litres: number; amount: number; odometer_km: number | null; station_name: string | null; payment_mode: string; receipt_path: string | null; vehicles?: { registration_number: string } | null; trips?: { trip_number: string } | null };
type Expense = { id: string; vehicle_id: string | null; trip_id: string | null; category: string; amount: number; payment_mode: string; expense_date: string; receipt_path: string | null; notes: string | null; automatic?: boolean; vehicles?: { registration_number: string } | null; trips?: { trip_number: string } | null };
type LedgerEntry = { id: string; customer_id: string; trip_id: string | null; entry_date: string; entry_type: "debit" | "credit"; amount: number; payment_mode: string | null; reference: string | null; customers?: { name: string } | null; trips?: { trip_number: string; material_name: string | null; quantity_tonnes: number } | null };
type FuelEfficiencyReport = {
  period: { from: string; to: string };
  summary: { entries: number; litres: number; amount: number; cash_amount: number; bank_amount: number; distance_km: number; km_per_litre: number | null; cost_per_km: number | null };
  vehicles: Array<{ vehicle_id: string | null; registration_number: string; entries: number; litres: number; amount: number; distance_km: number; km_per_litre: number | null; cost_per_km: number | null; last_odometer_km: number | null; last_filled_at: string | null }>;
  recent_entries: Array<{ id: string; vehicle_id: string | null; previous_odometer_km: number | null; odometer_km: number | null; distance_km: number | null; km_per_litre: number | null }>;
};
type ScalableTrip = { id: string; trip_number: string; vehicle_id: string | null; driver_id: string | null; customer_id: string | null; vehicle_registration: string | null; driver_name: string | null; customer_name: string | null; material_name: string | null; origin: string; destination: string; quantity_tonnes: number; distance_km: number; empty_distance_km: number; total_distance_km: number; freight_amount: number; cost: number; status: string; scheduled_start_at: string | null; report_date: string };
type ProfitDimension = { dimension: "truck" | "driver" | "customer" | "material" | "route"; entity_id: string | null; label: string; trips: number; weight_tonnes: number; distance_km: number; empty_distance_km: number; total_distance_km: number; revenue: number; cost: number; profit: number };
type ScalableReport = { period: { from: string; to: string }; summary: { trips: number; revenue: number; cost: number; profit: number; loaded_km: number; empty_km: number; empty_running_pct: number }; trips: ScalableTrip[]; profitability: ProfitDimension[]; ageing: Array<{ customer_id: string; customer: string; balance: number; age_days: number; bucket: string; bucket_0_30: number; bucket_31_60: number; bucket_61_90: number; bucket_90_plus: number }>; utilization: Array<{ id: string; registration_number: string; completed_trips: number; active_days: number; period_days: number; loaded_km: number; empty_km: number; total_km: number; empty_running_pct: number; utilization_pct: number }> };
type ReportSchedule = { id: string; name: string; report_type: string; format: string; frequency: string; recipients: string[]; next_run_at: string | null; status: string };

const money = (value: number | string | null | undefined) => `INR ${Number(value ?? 0).toLocaleString("en-IN", { maximumFractionDigits: 2 })}`;
const today = () => new Date().toISOString().slice(0, 10);
const tripStatus: Record<string, string> = { scheduled: "Planned", loading: "Planned", in_transit: "In Progress", delivered: "Completed", delayed: "In Progress", cancelled: "Cancelled" };

function Modal({ title, subtitle, children, saving, valid = true, onClose, onSave }: { title: string; subtitle: string; children: React.ReactNode; saving: boolean; valid?: boolean; onClose: () => void; onSave: () => void }) {
  return <div className="vehicle-modal-layer"><button className="modal-backdrop" aria-label="Close" onClick={onClose} /><section className="vehicle-dialog transport-dialog" role="dialog" aria-modal="true"><div className="vehicle-dialog-header"><div><span className="module-eyebrow">Live database</span><h2>{title}</h2><p>{subtitle}</p></div><button className="data-icon-button" onClick={onClose} aria-label="Close"><X size={18} /></button></div>{children}<div className="vehicle-dialog-actions"><button className="module-button module-button-secondary" onClick={onClose}>Cancel</button><button className="module-button module-button-primary" disabled={saving || !valid} onClick={onSave}>{saving ? "Saving..." : "Save"}</button></div></section></div>;
}

function PageHeader({ icon: Icon, eyebrow, title, subtitle, action, onAdd }: { icon: typeof Truck; eyebrow: string; title: string; subtitle: string; action: string; onAdd: () => void }) {
  return <header className="module-header"><div className="module-header-copy"><div className="module-eyebrow"><Icon size={15} /> {eyebrow}</div><h1>{title}</h1><p>{subtitle}</p></div><button className="module-button module-button-primary" onClick={onAdd}><Plus size={16} /> {action}</button></header>;
}

function TripView() {
  const empty = { trip_number: "", customer_id: "", vehicle_id: "", driver_id: "", origin: "", destination: "", material_name: "", status: "scheduled", rate_type: "fixed", rate: "", quantity_tonnes: "", distance_km: "", empty_distance_km: "", scheduled_start_at: today(), notes: "" };
  const newTripExpense = () => ({ id: crypto.randomUUID(), category: "toll", amount: "", payment_mode: "cash", notes: "" });
  const [records, setRecords] = useState<Trip[]>([]);
  const [resources, setResources] = useState<Resources>({ vehicles: [], drivers: [], customers: [] });
  const [pagination, setPagination] = useState<PaginatedTrips["pagination"]>({ page: 1, pageSize: 25, total: 0, totalPages: 1 });
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(25);
  const [searchInput, setSearchInput] = useState("");
  const [debouncedSearch, setDebouncedSearch] = useState("");
  const [filters, setFilters] = useState<TripFilters>({ status: "", vehicleId: "", driverId: "", customerId: "", material: "", paymentStatus: "", dateFrom: "", dateTo: "", sort: "newest" });
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [loading, setLoading] = useState(true);
  const requestIdRef = useRef(0);
  const [form, setForm] = useState(empty); const [newParty, setNewParty] = useState({ name: "", phone: "", contact_name: "" }); const [tripExpenses, setTripExpenses] = useState<Array<ReturnType<typeof newTripExpense>>>([]); const [editing, setEditing] = useState<string | null>(null); const [open, setOpen] = useState(false); const [saving, setSaving] = useState(false); const [error, setError] = useState<string | null>(null);
  const load = useCallback(async () => {
    const requestId = ++requestIdRef.current;
    const query = new URLSearchParams({ page: String(page), pageSize: String(pageSize), sort: filters.sort });
    const queryValues = { search: debouncedSearch.trim(), status: filters.status, vehicleId: filters.vehicleId, driverId: filters.driverId, customerId: filters.customerId, material: filters.material.trim(), paymentStatus: filters.paymentStatus, dateFrom: filters.dateFrom, dateTo: filters.dateTo };
    Object.entries(queryValues).forEach(([key, value]) => { if (value) query.set(key, value); });
    setLoading(true);
    try {
      const result = await fleetoraApi<PaginatedTrips>(`/trips/paginated?${query.toString()}`);
      if (requestId !== requestIdRef.current) return;
      const nextPagination = result.pagination ?? { page, pageSize, total: 0, totalPages: 1 };
      const totalPages = Math.max(1, Number(nextPagination.totalPages) || 1);
      setRecords(result.data ?? []);
      setPagination({ page: Number(nextPagination.page) || page, pageSize: Number(nextPagination.pageSize) || pageSize, total: Math.max(0, Number(nextPagination.total) || 0), totalPages });
      if (page > totalPages) setPage(totalPages);
      setError(null);
    } catch (e) {
      if (requestId === requestIdRef.current) setError(e instanceof Error ? e.message : "Could not load trips.");
    } finally {
      if (requestId === requestIdRef.current) setLoading(false);
    }
  }, [debouncedSearch, filters, page, pageSize]);
  useEffect(() => {
    let active = true;
    void fleetoraApi<Resources>("/resources").then((refs) => { if (active) setResources(refs); }).catch((e: unknown) => { if (active) setError(e instanceof Error ? e.message : "Could not load trip filters."); });
    return () => { active = false; };
  }, []);
  useEffect(() => {
    const timer = window.setTimeout(() => setDebouncedSearch(searchInput.trim()), 400);
    return () => window.clearTimeout(timer);
  }, [searchInput]);
  useEffect(() => {
    const timer = window.setTimeout(() => void load(), 0);
    return () => window.clearTimeout(timer);
  }, [load]);
  function updateFilter<Key extends keyof TripFilters>(key: Key, value: TripFilters[Key]) { setFilters(current => ({ ...current, [key]: value })); setPage(1); }
  function clearFilters() { setSearchInput(""); setDebouncedSearch(""); setFilters({ status: "", vehicleId: "", driverId: "", customerId: "", material: "", paymentStatus: "", dateFrom: "", dateTo: "", sort: "newest" }); setPage(1); }
  const amount = form.rate_type === "per_ton" ? Number(form.rate) * Number(form.quantity_tonnes) : form.rate_type === "per_km" ? Number(form.rate) * Number(form.distance_km) : Number(form.rate);
  function add() { setEditing(null); setNewParty({ name: "", phone: "", contact_name: "" }); setTripExpenses([]); setForm({ ...empty, scheduled_start_at: today(), trip_number: `TRIP-${Date.now().toString().slice(-6)}` }); setOpen(true); }
  function edit(t: Trip) { setEditing(t.id); setTripExpenses([]); setForm({ trip_number: t.trip_number, customer_id: t.customer_id ?? "", vehicle_id: t.vehicle_id ?? "", driver_id: t.driver_id ?? "", origin: t.origin, destination: t.destination, material_name: t.material_name ?? "", status: t.status, rate_type: t.rate_type, rate: String(t.rate), quantity_tonnes: String(t.quantity_tonnes), distance_km: String(t.distance_km), empty_distance_km: String(t.empty_distance_km ?? 0), scheduled_start_at: t.scheduled_start_at?.slice(0, 10) ?? today(), notes: "" }); setOpen(true); }
  async function remove(t: Trip) { if (!window.confirm(`Delete trip “${t.trip_number}”? This cannot be undone.`)) return; try { await fleetoraApi(`/trips/${t.id}`, { method: "DELETE" }); await load(); } catch (e) { setError(e instanceof Error ? e.message : "Could not delete trip."); } }
  function updateTripExpense(id: string, patch: Partial<ReturnType<typeof newTripExpense>>) { setTripExpenses(rows => rows.map(row => row.id === id ? { ...row, ...patch } : row)); }
  async function save() { setSaving(true); try { let partyId = form.customer_id; if (partyId === "__new__") { const created = await fleetoraApi<Customer[]>("/customers", { method: "POST", body: JSON.stringify({ ...newParty, status: "active", credit_limit: 0, payment_terms_days: 30 }) }); partyId = created[0]?.id ?? ""; if (!partyId) throw new Error("The new party could not be created."); } const body = { ...form, customer_id: partyId || null, vehicle_id: form.vehicle_id || null, driver_id: form.driver_id || null, rate: Number(form.rate), quantity_tonnes: Number(form.quantity_tonnes), distance_km: Number(form.distance_km), empty_distance_km: Number(form.empty_distance_km), scheduled_start_at: form.scheduled_start_at || null, actual_end_at: form.status === "delivered" ? new Date().toISOString() : null }; const saved = await fleetoraApi<Trip[]>(editing ? `/trips/${editing}` : "/trips", { method: editing ? "PATCH" : "POST", body: JSON.stringify(body) }); const tripId = editing ?? saved[0]?.id; if (tripId && tripExpenses.length) { await Promise.all(tripExpenses.map(expense => fleetoraApi("/expenses", { method: "POST", body: JSON.stringify({ trip_id: tripId, vehicle_id: form.vehicle_id || null, category: expense.category, amount: Number(expense.amount), payment_mode: expense.payment_mode, expense_date: form.scheduled_start_at || today(), notes: expense.notes || null }) }))); } setOpen(false); await load(); } catch (e) { setError(e instanceof Error ? e.message : "Could not save trip."); } finally { setSaving(false); } }
  const completedOnPage = records.filter(r => r.status === "delivered").reduce((sum, trip) => sum + Number(trip.freight_amount), 0);
  const activeFilterCount = [filters.status, filters.vehicleId, filters.driverId, filters.customerId, filters.material, filters.paymentStatus, filters.dateFrom, filters.dateTo].filter(Boolean).length;
  const firstRecord = pagination.total === 0 ? 0 : (pagination.page - 1) * pagination.pageSize + 1;
  const lastRecord = pagination.total === 0 ? 0 : Math.min(firstRecord + records.length - 1, pagination.total);
  const pageNumbers = Array.from(new Set([1, 2, pagination.page - 1, pagination.page, pagination.page + 1, pagination.totalPages - 1, pagination.totalPages].filter(number => number >= 1 && number <= pagination.totalPages))).sort((a, b) => a - b);
  return <motion.main className="module-page trip-module-page" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
    <PageHeader icon={Truck} eyebrow="Dispatch and income" title="Trip control" subtitle="Search and manage every trip without loading your full trip history into the browser." action="Create trip" onAdd={add} />
    <section className="module-kpis" aria-label="Trip page summary">
      {[["Total trips", pagination.total, "Across the active workspace"], ["On this page", records.length, `${pagination.pageSize} records per page`], ["In progress", records.filter(r => r.status === "in_transit").length, "On this page"], ["Completed income", money(completedOnPage), "On this page"]].map(([label, value, detail]) => <article className="module-kpi module-tone-blue" key={String(label)}><span className="module-kpi-icon"><Truck size={18} /></span><div className="module-kpi-copy"><span>{String(label)}</span><strong>{String(value)}</strong><small>{String(detail)}</small></div></article>)}
    </section>
    {error && <div className="module-inline-error" role="alert">{error}</div>}
    <section className="module-data-panel trip-register-panel">
      <div className="module-section-heading">
        <div>
          <h2>Trip register</h2>
          <p>Server-side search, filters and pagination keep even large trip histories fast.</p>
        </div>
        <span className="module-record-count">{pagination.total.toLocaleString("en-IN")} trips</span>
      </div>
      <div className="trip-query-toolbar">
        <label className="filter-search trip-search-field">
          <Search size={16} aria-hidden="true" />
          <span className="data-visually-hidden">Search trip records</span>
          <input value={searchInput} onChange={event => { setSearchInput(event.target.value); setPage(1); }} placeholder="Search Trip ID, LR, invoice, truck, driver, customer or route" />
          {searchInput && <button type="button" aria-label="Clear search" onClick={() => { setSearchInput(""); setPage(1); }}><X size={14} /></button>}
        </label>
        <button type="button" className={["trip-filter-toggle", filtersOpen && "trip-filter-toggle-active"].filter(Boolean).join(" ")} onClick={() => setFiltersOpen(openFilters => !openFilters)} aria-expanded={filtersOpen} aria-controls="trip-advanced-filters"><Filter size={15} /> Filters{activeFilterCount ? " (" + activeFilterCount + ")" : ""}</button>
        <label className="trip-select-control">
          <span>Sort</span>
          <select value={filters.sort} onChange={event => updateFilter("sort", event.target.value)}>
            <option value="newest">Newest first</option>
            <option value="oldest">Oldest first</option>
            <option value="freight">Highest freight</option>
            <option value="driver">Driver A-Z</option>
            <option value="vehicle">Vehicle A-Z</option>
          </select>
        </label>
        <label className="trip-select-control trip-page-size-control">
          <span>Rows</span>
          <select value={pageSize} onChange={event => { setPageSize(Number(event.target.value)); setPage(1); }}>
            {[25, 50, 100].map(size => <option key={size} value={size}>{size} / page</option>)}
          </select>
        </label>
      </div>
      <div id="trip-advanced-filters" className={["trip-filter-grid", filtersOpen && "trip-filter-grid-open"].filter(Boolean).join(" ")} hidden={!filtersOpen}>
        <label><span>Status</span><select value={filters.status} onChange={event => updateFilter("status", event.target.value)}><option value="">All statuses</option>{Object.entries(tripStatus).map(([value, label]) => <option key={value} value={value}>{label}</option>)}</select></label>
        <label><span>Vehicle</span><select value={filters.vehicleId} onChange={event => updateFilter("vehicleId", event.target.value)}><option value="">All vehicles</option>{resources.vehicles.map(vehicle => <option key={vehicle.id} value={vehicle.id}>{vehicle.registration_number}</option>)}</select></label>
        <label><span>Driver</span><select value={filters.driverId} onChange={event => updateFilter("driverId", event.target.value)}><option value="">All drivers</option>{resources.drivers.map(driver => <option key={driver.id} value={driver.id}>{driver.full_name}</option>)}</select></label>
        <label><span>Customer</span><select value={filters.customerId} onChange={event => updateFilter("customerId", event.target.value)}><option value="">All customers</option>{resources.customers.map(customer => <option key={customer.id} value={customer.id}>{customer.name}</option>)}</select></label>
        <label><span>Material</span><input value={filters.material} onChange={event => updateFilter("material", event.target.value)} placeholder="Any material" /></label>
        <label><span>Payment</span><select value={filters.paymentStatus} onChange={event => updateFilter("paymentStatus", event.target.value)}><option value="">Any payment status</option><option value="paid">Paid</option><option value="outstanding">Outstanding</option><option value="uninvoiced">Uninvoiced</option></select></label>
        <label><span>From date</span><input type="date" value={filters.dateFrom} onChange={event => updateFilter("dateFrom", event.target.value)} /></label>
        <label><span>To date</span><input type="date" value={filters.dateTo} onChange={event => updateFilter("dateTo", event.target.value)} /></label>
        <button type="button" className="trip-clear-filters" onClick={clearFilters} disabled={!searchInput && !activeFilterCount && filters.sort === "newest"}><SlidersHorizontal size={14} /> Clear filters</button>
      </div>
      <div className="data-table-wrap trip-table-wrap" aria-busy={loading}>
        <table className="data-table enterprise-table trip-data-table">
          <thead><tr><th>Trip / date</th><th>Customer</th><th>Vehicle / driver</th><th>Material / weight</th><th>Route</th><th>Rate</th><th>Freight</th><th>Status</th><th className="data-actions-heading">Actions</th></tr></thead>
          <tbody>
            {records.map(trip => <tr key={trip.id} className="data-table-row">
              <td><span className="data-primary-cell"><strong>{trip.trip_number}</strong><small>{trip.scheduled_start_at ? new Date(trip.scheduled_start_at).toLocaleDateString("en-IN") : "Date not set"}</small></span></td>
              <td>{trip.customers?.name ?? trip.customer_name ?? "Not assigned"}</td>
              <td><span className="data-primary-cell"><strong>{trip.vehicles?.registration_number ?? trip.vehicle_registration ?? "No truck"}</strong><small>{trip.drivers?.full_name ?? trip.driver_name ?? "No driver"}</small></span></td>
              <td><span className="data-primary-cell"><strong>{trip.material_name ?? "Not recorded"}</strong><small>{Number(trip.quantity_tonnes) > 0 ? Number(trip.quantity_tonnes).toLocaleString("en-IN") + " tonnes" : "Weight not recorded"}</small></span></td>
              <td><span className="trip-route-cell"><strong>{trip.origin}</strong><span>{trip.destination}</span></span></td>
              <td><span className="data-primary-cell"><strong>{trip.rate_type.replace("_", " ")}</strong><small>@ {money(trip.rate)}</small></span></td>
              <td className="data-money data-money-positive">{money(trip.freight_amount)}</td>
              <td><span className={["status-pill", "status-" + trip.status.replace("_", "-")].join(" ")}>{tripStatus[trip.status] ?? trip.status}</span></td>
              <td className="data-row-actions"><div className="live-record-actions"><button className="data-icon-button" title="Edit" aria-label={"Edit " + trip.trip_number} onClick={() => edit(trip)}><Pencil size={16} /></button><button className="data-icon-button live-delete-button" title="Delete" aria-label={"Delete " + trip.trip_number} onClick={() => void remove(trip)}><Trash2 size={16} /></button></div></td>
            </tr>)}
          </tbody>
        </table>
        {!loading && !records.length && <div className="data-empty"><Truck size={22} /><strong>No matching trips</strong><span>Try clearing a filter, adjusting your date range, or creating a new trip.</span></div>}
        {loading && !records.length && <div className="trip-table-loading"><span className="trip-table-loading-dot" /><span>Loading trip records...</span></div>}
      </div>
      <footer className="trip-pagination">
        <p>Showing <strong>{firstRecord.toLocaleString("en-IN")}–{lastRecord.toLocaleString("en-IN")}</strong> of <strong>{pagination.total.toLocaleString("en-IN")}</strong> trips</p>
        <nav aria-label="Trip pages" className="trip-page-navigation">
          <button type="button" onClick={() => setPage(current => Math.max(1, current - 1))} disabled={loading || pagination.page <= 1}><ChevronLeft size={14} /> Previous</button>
          <div className="trip-page-numbers">
            {pageNumbers.map((number, index) => <span className="trip-page-slot" key={number}>{index > 0 && number - pageNumbers[index - 1] > 1 && <span className="trip-page-gap" aria-hidden="true">...</span>}<button type="button" aria-label={"Page " + number} aria-current={pagination.page === number ? "page" : undefined} className={pagination.page === number ? "trip-page-active" : ""} onClick={() => setPage(number)} disabled={loading}>{number}</button></span>)}
          </div>
          <button type="button" onClick={() => setPage(current => Math.min(pagination.totalPages, current + 1))} disabled={loading || pagination.page >= pagination.totalPages}>Next <ChevronRight size={14} /></button>
        </nav>
      </footer>
    </section>
    <AnimatePresence>{open && <Modal title={editing ? "Edit trip" : "Create trip"} subtitle="Select trip details and optionally add multiple linked expenses." saving={saving} valid={Boolean(form.trip_number && form.scheduled_start_at && form.customer_id && (form.customer_id !== "__new__" || newParty.name.trim()) && form.origin && form.destination && form.material_name && form.quantity_tonnes && form.rate && tripExpenses.every(expense => Number(expense.amount) > 0))} onClose={() => setOpen(false)} onSave={() => void save()}>
      <div className="vehicle-form-grid transport-form">
        <label><span>Trip number</span><input value={form.trip_number} onChange={e => setForm({ ...form, trip_number: e.target.value })} /></label>
        <label><span>Trip date</span><input type="date" value={form.scheduled_start_at} onChange={e => setForm({ ...form, scheduled_start_at: e.target.value })} /></label>
        <label><span>Party option</span><select value={form.customer_id} onChange={e => setForm({ ...form, customer_id: e.target.value })}><option value="">Select existing party</option>{resources.customers.map(x => <option key={x.id} value={x.id}>{x.name}</option>)}<option value="__new__">+ Add new party</option></select></label>
        {form.customer_id === "__new__" && <><label><span>New party name</span><input value={newParty.name} onChange={e => setNewParty({ ...newParty, name: e.target.value })} placeholder="Required" /></label><label><span>Party phone</span><input value={newParty.phone} onChange={e => setNewParty({ ...newParty, phone: e.target.value })} /></label><label className="vehicle-form-wide"><span>Contact person</span><input value={newParty.contact_name} onChange={e => setNewParty({ ...newParty, contact_name: e.target.value })} /></label></>}
        <label><span>Truck</span><select value={form.vehicle_id} onChange={e => setForm({ ...form, vehicle_id: e.target.value })}><option value="">Select truck</option>{resources.vehicles.map(x => <option key={x.id} value={x.id}>{x.registration_number}</option>)}</select></label>
        <label><span>Driver</span><select value={form.driver_id} onChange={e => setForm({ ...form, driver_id: e.target.value })}><option value="">Select driver</option>{resources.drivers.map(x => <option key={x.id} value={x.id}>{x.full_name}</option>)}</select></label>
        <label><span>Origin</span><input value={form.origin} onChange={e => setForm({ ...form, origin: e.target.value })} /></label>
        <label><span>Destination</span><input value={form.destination} onChange={e => setForm({ ...form, destination: e.target.value })} /></label>
        <label><span>Material transported</span><input value={form.material_name} onChange={e => setForm({ ...form, material_name: e.target.value })} placeholder="e.g. Cement, steel, grain" /></label>
        <label><span>Material weight (tonnes)</span><input type="number" min="0.01" step="0.01" value={form.quantity_tonnes} onChange={e => setForm({ ...form, quantity_tonnes: e.target.value })} /></label>
        <label><span>Rate type</span><select value={form.rate_type} onChange={e => setForm({ ...form, rate_type: e.target.value })}><option value="fixed">Fixed</option><option value="per_ton">Per ton</option><option value="per_km">Per km</option></select></label>
        <label><span>Rate</span><input type="number" min="0" value={form.rate} onChange={e => setForm({ ...form, rate: e.target.value })} /></label>
        <label><span>Loaded distance (km)</span><input type="number" min="0" value={form.distance_km} onChange={e => setForm({ ...form, distance_km: e.target.value })} /></label>
        <label><span>Empty / deadhead distance (km)</span><input type="number" min="0" value={form.empty_distance_km} onChange={e => setForm({ ...form, empty_distance_km: e.target.value })} /></label>
        <label><span>Status</span><select value={form.status} onChange={e => setForm({ ...form, status: e.target.value })}><option value="scheduled">Planned</option><option value="in_transit">In Progress</option><option value="delivered">Completed</option><option value="cancelled">Cancelled</option></select></label>
        <div className="vehicle-form-wide trip-expenses-editor"><div className="trip-expenses-heading"><div><strong>Trip expenses</strong><span>Add toll, loading, allowance, repair, fuel or other costs separately.</span></div><button type="button" className="module-button module-button-secondary" onClick={() => setTripExpenses(rows => [...rows, newTripExpense()])}><Plus size={15} /> Add expense</button></div>{tripExpenses.map((expense, index) => <div className="trip-expense-row" key={expense.id}><span className="trip-expense-number">#{index + 1}</span><label><span>Category</span><select value={expense.category} onChange={e => updateTripExpense(expense.id, { category: e.target.value })}>{["fuel", "toll", "driver_allowance", "loading", "repair", "maintenance", "other"].map(x => <option key={x} value={x}>{x.replace("_", " ")}</option>)}</select></label><label><span>Amount</span><input type="number" min="0.01" value={expense.amount} onChange={e => updateTripExpense(expense.id, { amount: e.target.value })} /></label><label><span>Payment mode</span><select value={expense.payment_mode} onChange={e => updateTripExpense(expense.id, { payment_mode: e.target.value })}><option value="cash">Cash</option><option value="bank">Bank</option></select></label><label><span>Notes</span><input value={expense.notes} onChange={e => updateTripExpense(expense.id, { notes: e.target.value })} /></label><button type="button" className="data-icon-button trip-expense-remove" aria-label={`Remove expense ${index + 1}`} onClick={() => setTripExpenses(rows => rows.filter(row => row.id !== expense.id))}><X size={16} /></button></div>)}{!tripExpenses.length && <div className="trip-expenses-empty">No linked expenses. Use Add expense to create one or more entries.</div>}</div>
        <div className="transport-calculation"><span>Calculated trip amount</span><strong>{money(amount)}</strong></div>
      </div>
    </Modal>}</AnimatePresence>
  </motion.main>;
}

async function uploadReceipt(file: File | null) {
  if (!file || !supabase) return null;
  const { data } = await supabase.auth.getUser(); if (!data.user) throw new Error("Please sign in again.");
  const safe = file.name.replace(/[^a-zA-Z0-9._-]/g, "-"); const path = `${data.user.id}/${crypto.randomUUID()}-${safe}`;
  const uploaded = await supabase.storage.from("receipts").upload(path, file); if (uploaded.error) throw uploaded.error; return path;
}

function CostView({ kind }: { kind: "fuel" | "expenses" }) {
  const fuelMode = kind === "fuel"; const empty: Record<string, string> = fuelMode ? { vehicle_id: "", trip_id: "", filled_at: new Date().toISOString().slice(0, 16), litres: "", amount: "", odometer_km: "", station_name: "", payment_mode: "cash", notes: "" } : { vehicle_id: "", trip_id: "", expense_date: today(), category: "toll", amount: "", payment_mode: "cash", notes: "" };
  const [records, setRecords] = useState<(FuelEntry | Expense)[]>([]); const [resources, setResources] = useState<Resources>({ vehicles: [], drivers: [], customers: [] }); const [trips, setTrips] = useState<Trip[]>([]); const [fuelReport, setFuelReport] = useState<FuelEfficiencyReport | null>(null); const [selectedVehicleId, setSelectedVehicleId] = useState(""); const [selectedTripId, setSelectedTripId] = useState(""); const [form, setForm] = useState<Record<string, string>>(empty); const [file, setFile] = useState<File | null>(null); const [existingReceipt, setExistingReceipt] = useState<string | null>(null); const [editingId, setEditingId] = useState<string | null>(null); const [open, setOpen] = useState(false); const [saving, setSaving] = useState(false); const [error, setError] = useState<string | null>(null);
  const load = useCallback(async () => {
    try {
      const [rows, refs, tripRows, fuelRows, fuelAnalytics] = await Promise.all([
        fleetoraApi<(FuelEntry | Expense)[]>(`/${kind}`),
        fleetoraApi<Resources>("/resources"),
        fleetoraApi<Trip[]>("/trips?limit=100"),
        fuelMode ? Promise.resolve([] as FuelEntry[]) : fleetoraApi<FuelEntry[]>("/fuel"),
        fuelMode ? fleetoraApi<FuelEfficiencyReport>("/reports/fuel-efficiency") : Promise.resolve(null),
      ]);
      const automaticFuel: Expense[] = fuelRows.map(f => ({ id: `fuel-${f.id}`, vehicle_id: f.vehicle_id, trip_id: f.trip_id, category: "fuel", amount: f.amount, payment_mode: f.payment_mode, expense_date: f.filled_at.slice(0, 10), receipt_path: f.receipt_path, notes: `${f.litres} L${f.station_name ? ` at ${f.station_name}` : ""}`, automatic: true, vehicles: f.vehicles, trips: f.trips }));
      const combined = fuelMode ? rows : [...(rows as Expense[]), ...automaticFuel].sort((a, b) => b.expense_date.localeCompare(a.expense_date));
      setRecords(combined); setResources(refs); setTrips(tripRows); setFuelReport(fuelAnalytics); setError(null);
    } catch (e) { setError(e instanceof Error ? e.message : "Could not load entries."); }
  }, [fuelMode, kind]);
  useEffect(() => {
    const timer = window.setTimeout(() => void load(), 0);
    return () => window.clearTimeout(timer);
  }, [load]);
  function add() { setEditingId(null); setExistingReceipt(null); setFile(null); setForm(empty); setOpen(true); }
  function editEntry(row: FuelEntry | Expense) { if (!fuelMode && (row as Expense).automatic) return; setEditingId(row.id); setExistingReceipt(row.receipt_path); setFile(null); setForm(fuelMode ? { vehicle_id: row.vehicle_id ?? "", trip_id: row.trip_id ?? "", filled_at: (row as FuelEntry).filled_at.slice(0, 16), litres: String((row as FuelEntry).litres), amount: String(row.amount), odometer_km: (row as FuelEntry).odometer_km == null ? "" : String((row as FuelEntry).odometer_km), station_name: (row as FuelEntry).station_name ?? "", payment_mode: row.payment_mode, notes: "" } : { vehicle_id: row.vehicle_id ?? "", trip_id: row.trip_id ?? "", expense_date: (row as Expense).expense_date, category: (row as Expense).category, amount: String(row.amount), payment_mode: row.payment_mode, notes: (row as Expense).notes ?? "" }); setOpen(true); }
  async function save() { setSaving(true); try { const uploaded = await uploadReceipt(file); const body = { ...form, vehicle_id: form.vehicle_id || null, trip_id: form.trip_id || null, litres: fuelMode ? Number(form.litres) : undefined, odometer_km: fuelMode && form.odometer_km ? Number(form.odometer_km) : null, amount: Number(form.amount), receipt_path: uploaded ?? existingReceipt }; await fleetoraApi(editingId ? `/${kind}/${editingId}` : `/${kind}`, { method: editingId ? "PATCH" : "POST", body: JSON.stringify(body) }); setOpen(false); setForm(empty); setFile(null); setEditingId(null); await load(); } catch (e) { setError(e instanceof Error ? e.message : "Could not save entry."); } finally { setSaving(false); } }
  async function removeEntry(row: FuelEntry | Expense) { if (!fuelMode && (row as Expense).automatic) return; if (!window.confirm(`Delete this ${fuelMode ? "fuel" : "expense"} entry of ${money(row.amount)}?`)) return; try { await fleetoraApi(`/${kind}/${row.id}`, { method: "DELETE" }); await load(); } catch (e) { setError(e instanceof Error ? e.message : "Could not delete entry."); } }
  const visibleRecords = records.filter(row => (!selectedVehicleId || row.vehicle_id === selectedVehicleId) && (!selectedTripId || row.trip_id === selectedTripId));
  const filteredTrips = selectedVehicleId ? trips.filter(trip => trip.vehicle_id === selectedVehicleId) : trips;
  const total = fuelMode ? Number(fuelReport?.summary.amount ?? 0) : visibleRecords.reduce((s, r) => s + Number(r.amount), 0);
  const litres = fuelMode ? Number(fuelReport?.summary.litres ?? 0) : 0;
  const bankPaid = fuelMode ? Number(fuelReport?.summary.bank_amount ?? 0) : visibleRecords.filter(r => r.payment_mode === "bank").reduce((s, r) => s + Number(r.amount), 0);
  const entryCount = fuelMode ? Number(fuelReport?.summary.entries ?? 0) : visibleRecords.length;
  const mileageById = useMemo(() => new Map((fuelReport?.recent_entries ?? []).map(row => [row.id, row.km_per_litre])), [fuelReport]);
  const truckStats = useMemo(() => (fuelReport?.vehicles ?? []).map(row => ({ name: row.registration_number, amount: Number(row.amount), count: Number(row.entries), litres: Number(row.litres), mileage: row.km_per_litre == null ? null : Number(row.km_per_litre) })), [fuelReport]);
  const expenseBreakdown = useMemo(() => { const grouped = new Map<string, { truck: string; trip: string; amount: number; count: number }>(); if (fuelMode) return []; (records as Expense[]).forEach(row => { const truck = row.vehicles?.registration_number ?? "General"; const trip = row.trips?.trip_number ?? "No trip"; const key = `${truck}|${trip}`; const current = grouped.get(key) ?? { truck, trip, amount: 0, count: 0 }; current.amount += Number(row.amount); current.count += 1; grouped.set(key, current); }); return [...grouped.values()].sort((a, b) => b.amount - a.amount); }, [records, fuelMode]);
  return <motion.main className="module-page" initial={{ opacity: 0 }} animate={{ opacity: 1 }}><PageHeader icon={fuelMode ? Fuel : Receipt} eyebrow={fuelMode ? "Fuel intelligence" : "Cost control"} title={fuelMode ? "Fuel management" : "Expense management"} subtitle={fuelMode ? "Record every fill-up and compare fuel cost by truck." : "Categorize cash and bank expenses with truck, trip and receipt links."} action={fuelMode ? "Add fuel" : "Add expense"} onAdd={add} />
    <section className="module-kpis">{[[fuelMode ? "Fuel cost" : "Total expenses", money(total)], [fuelMode ? "Litres filled" : "Cash paid", fuelMode ? litres.toLocaleString("en-IN") : money(visibleRecords.filter(r => r.payment_mode === "cash").reduce((s, r) => s + Number(r.amount), 0))], ["Bank paid", money(bankPaid)], ["Entries", entryCount]].map(([label, value]) => <article className="module-kpi module-tone-amber" key={label}><span className="module-kpi-icon"><Droplets size={18} /></span><div className="module-kpi-copy"><span>{label}</span><strong>{value}</strong><small>{fuelMode ? "Complete database" : "Live records"}</small></div></article>)}</section>{error && <div className="module-inline-error">{error}</div>}
    {!fuelMode && <div className="filter-bar report-filter expense-breakdown-filter"><label><span>Truck</span><select value={selectedVehicleId} onChange={event => { setSelectedVehicleId(event.target.value); setSelectedTripId(""); }}><option value="">All trucks</option>{resources.vehicles.map(vehicle => <option key={vehicle.id} value={vehicle.id}>{vehicle.registration_number}</option>)}</select></label><label><span>Trip</span><select value={selectedTripId} onChange={event => setSelectedTripId(event.target.value)}><option value="">All trips</option>{filteredTrips.map(trip => <option key={trip.id} value={trip.id}>{trip.trip_number}</option>)}</select></label><button className="module-button module-button-secondary" onClick={() => { setSelectedVehicleId(""); setSelectedTripId(""); }}>Clear filters</button></div>}
    <div className="module-content-grid">
      <section className="module-data-panel"><div className="module-section-heading"><div><h2>{fuelMode ? "Fuel register" : "Expense register"}</h2><p>{fuelMode ? "Mileage is calculated from consecutive odometer readings for each truck" : "Filter expenses separately by truck and trip"}</p></div><span className="module-record-count">{visibleRecords.length} entries</span></div><div className="data-table-wrap"><table className="data-table"><thead><tr><th>Date</th><th>Truck</th>{!fuelMode && <th>Trip</th>}<th>{fuelMode ? "Litres / Station" : "Category"}</th>{fuelMode && <th>Mileage</th>}<th>Mode</th><th>Amount</th><th>Receipt</th><th>Actions</th></tr></thead><tbody>{visibleRecords.map(r => { const mileage = fuelMode ? mileageById.get(r.id) : null; const automatic = !fuelMode && Boolean((r as Expense).automatic); return <tr key={r.id}><td>{new Date(fuelMode ? (r as FuelEntry).filled_at : (r as Expense).expense_date).toLocaleDateString("en-IN")}</td><td>{r.vehicles?.registration_number ?? "General"}</td>{!fuelMode && <td>{r.trips?.trip_number ?? "No trip"}</td>}<td>{fuelMode ? `${(r as FuelEntry).litres} L / ${(r as FuelEntry).station_name ?? "-"}` : <span className="data-primary-cell"><strong>{(r as Expense).category.replace("_", " ")}</strong>{automatic && <small>Manage in Fuel section</small>}</span>}</td>{fuelMode && <td><span className="data-primary-cell"><strong>{mileage ? `${mileage.toFixed(2)} km/L` : "Pending"}</strong><small>{mileage ? "Automatically calculated" : "Needs previous odometer"}</small></span></td>}<td>{r.payment_mode}</td><td>{money(r.amount)}</td><td>{r.receipt_path ? <span className="status-pill status-completed"><FileText size={12} /> Attached</span> : "-"}</td><td>{automatic ? <span className="module-record-count">Fuel entry</span> : <div className="live-record-actions"><button className="data-icon-button" title="Edit" aria-label="Edit entry" onClick={() => editEntry(r)}><Pencil size={16} /></button><button className="data-icon-button live-delete-button" title="Delete" aria-label="Delete entry" onClick={() => void removeEntry(r)}><Trash2 size={16} /></button></div>}</td></tr>; })}</tbody></table>{!visibleRecords.length && <div className="data-empty"><Receipt size={22} /><strong>No entries for these filters</strong></div>}</div></section>
      <aside className="panel-insight"><div className="panel-insight-heading"><Truck size={16} /> {fuelMode ? "Per-truck analytics" : "Truck / trip breakdown"}</div><h2>{fuelMode ? "Fuel mileage and cost" : "Expenses separated by trip"}</h2><div className="panel-insight-list">{fuelMode ? truckStats.slice(0, 8).map(x => <div className="panel-insight-item" key={x.name}><span>{x.name}</span><strong>{x.mileage ? `${x.mileage.toFixed(2)} km/L` : "Mileage pending"} / {x.litres.toFixed(1)} L / {money(x.amount)}</strong></div>) : expenseBreakdown.slice(0, 12).map(item => <div className="panel-insight-item" key={`${item.truck}-${item.trip}`}><span>{item.truck}<small>{item.trip} / {item.count} entries</small></span><strong>{money(item.amount)}</strong></div>)}</div></aside>
    </div>
    <AnimatePresence>{open && <Modal title={fuelMode ? "Record fuel" : "Record expense"} subtitle="Attach an image or PDF receipt up to 10 MB." saving={saving} valid={Boolean(form.amount && (fuelMode ? form.vehicle_id && form.litres : form.category))} onClose={() => setOpen(false)} onSave={() => void save()}><div className="vehicle-form-grid transport-form"><label><span>Truck (optional for general expense)</span><select value={form.vehicle_id} onChange={e => setForm({ ...form, vehicle_id: e.target.value })}><option value="">General / select truck</option>{resources.vehicles.map(v => <option key={v.id} value={v.id}>{v.registration_number}</option>)}</select></label><label><span>Trip (optional)</span><select value={form.trip_id} onChange={e => setForm({ ...form, trip_id: e.target.value })}><option value="">No trip</option>{trips.map(t => <option key={t.id} value={t.id}>{t.trip_number}</option>)}</select></label>{fuelMode ? <><label><span>Litres</span><input type="number" min="0" value={form.litres} onChange={e => setForm({ ...form, litres: e.target.value })} /></label><label><span>Odometer km</span><input type="number" min="0" value={form.odometer_km} onChange={e => setForm({ ...form, odometer_km: e.target.value })} /></label><label><span>Station</span><input value={form.station_name} onChange={e => setForm({ ...form, station_name: e.target.value })} /></label><label><span>Filled at</span><input type="datetime-local" value={form.filled_at} onChange={e => setForm({ ...form, filled_at: e.target.value })} /></label></> : <><label><span>Category</span><select value={form.category} onChange={e => setForm({ ...form, category: e.target.value })}>{["fuel", "toll", "driver_allowance", "loading", "repair", "maintenance", "office", "salary", "other"].map(x => <option key={x}>{x}</option>)}</select></label><label><span>Expense date</span><input type="date" value={form.expense_date} onChange={e => setForm({ ...form, expense_date: e.target.value })} /></label></>}<label><span>Amount</span><input type="number" min="0" value={form.amount} onChange={e => setForm({ ...form, amount: e.target.value })} /></label><label><span>Payment mode</span><select value={form.payment_mode} onChange={e => setForm({ ...form, payment_mode: e.target.value })}><option value="cash">Cash</option><option value="bank">Bank</option></select></label><label className="vehicle-form-wide"><span>Bill / receipt</span><input type="file" accept="image/jpeg,image/png,image/webp,application/pdf" onChange={e => setFile(e.target.files?.[0] ?? null)} /></label><label className="vehicle-form-wide"><span>Notes</span><input value={form.notes} onChange={e => setForm({ ...form, notes: e.target.value })} /></label></div></Modal>}</AnimatePresence>
  </motion.main>;
}

function DirectoryView({ kind }: { kind: "drivers" | "customers" }) {
  const driverMode = kind === "drivers"; const blank: Record<string, string> = driverMode ? { full_name: "", phone: "", license_number: "", license_expiry: "", status: "available" } : { name: "", phone: "", contact_name: "", email: "", credit_limit: "0", payment_terms_days: "30", status: "active" };
  const [rows, setRows] = useState<(Driver | Customer)[]>([]); const [ledgerRows, setLedgerRows] = useState<LedgerEntry[]>([]); const [form, setForm] = useState<Record<string, string>>(blank); const [editingId, setEditingId] = useState<string | null>(null); const [open, setOpen] = useState(false); const [saving, setSaving] = useState(false); const [error, setError] = useState<string | null>(null);
  const load = useCallback(async () => { try { const [directory, ledger] = await Promise.all([fleetoraApi<(Driver | Customer)[]>(`/${kind}?limit=100`), driverMode ? Promise.resolve([] as LedgerEntry[]) : fleetoraApi<LedgerEntry[]>("/ledger")]); setRows(directory); setLedgerRows(ledger); setError(null); } catch (e) { setError(e instanceof Error ? e.message : "Could not load records."); } }, [driverMode, kind]);
  useEffect(() => {
    const timer = window.setTimeout(() => void load(), 0);
    return () => window.clearTimeout(timer);
  }, [load]);
  const customerBalance = (customerId: string) => ledgerRows.filter(row => row.customer_id === customerId).reduce((sum, row) => sum + (row.entry_type === "debit" ? Number(row.amount) : -Number(row.amount)), 0);
  function add() { setEditingId(null); setForm(blank); setOpen(true); }
  function editEntry(row: Driver | Customer) { setEditingId(row.id); setForm(driverMode ? { full_name: (row as Driver).full_name, phone: row.phone ?? "", license_number: (row as Driver).license_number ?? "", license_expiry: (row as Driver).license_expiry?.slice(0, 10) ?? "", status: row.status } : { name: (row as Customer).name, phone: row.phone ?? "", contact_name: (row as Customer).contact_name ?? "", email: (row as Customer).email ?? "", credit_limit: String((row as Customer).credit_limit ?? 0), payment_terms_days: String((row as Customer).payment_terms_days ?? 30), status: row.status }); setOpen(true); }
  async function save() { setSaving(true); try { const body = driverMode ? form : { ...form, credit_limit: Number(form.credit_limit), payment_terms_days: Number(form.payment_terms_days) }; await fleetoraApi(editingId ? `/${kind}/${editingId}` : `/${kind}`, { method: editingId ? "PATCH" : "POST", body: JSON.stringify(body) }); setOpen(false); setEditingId(null); setForm(blank); await load(); } catch (e) { setError(e instanceof Error ? e.message : "Could not save."); } finally { setSaving(false); } }
  async function removeEntry(row: Driver | Customer) { const name = driverMode ? (row as Driver).full_name : (row as Customer).name; if (!window.confirm(`Delete “${name}”? This cannot be undone.`)) return; try { await fleetoraApi(`/${kind}/${row.id}`, { method: "DELETE" }); await load(); } catch (e) { setError(e instanceof Error ? e.message : "Could not delete record."); } }
  return <motion.main className="module-page" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
    <PageHeader icon={driverMode ? Users : Wallet} eyebrow={driverMode ? "Workforce" : "Party accounts"} title={driverMode ? "Driver workforce" : "Customer and party accounts"} subtitle={driverMode ? "Drivers added here can be assigned to trips." : "Parties added here receive completed trip amounts in their ledger."} action={driverMode ? "Add driver" : "Add party"} onAdd={add} />
    {error && <div className="module-inline-error">{error}</div>}
    <section className="module-data-panel"><div className="module-section-heading"><div><h2>{driverMode ? "Driver directory" : "Party directory"}</h2><p>{driverMode ? "Live operational master data" : "Live credit limits and ledger balances"}</p></div><span className="module-record-count">{rows.length} records</span></div><div className="data-table-wrap"><table className="data-table"><thead><tr><th>Name</th><th>Phone</th><th>{driverMode ? "License" : "Credit limit"}</th>{!driverMode && <th>Ledger / Udhar</th>}<th>Status</th><th>Actions</th></tr></thead><tbody>{rows.map(row => { const balance = driverMode ? 0 : customerBalance(row.id); const name = driverMode ? (row as Driver).full_name : (row as Customer).name; return <tr key={row.id}><td><strong>{name}</strong></td><td>{row.phone ?? "-"}</td><td>{driverMode ? (row as Driver).license_number ?? "-" : money((row as Customer).credit_limit)}</td>{!driverMode && <td className={balance > 0 ? "data-money-negative" : "data-money-positive"}><strong>{money(balance)}</strong></td>}<td><span className={`status-pill status-${row.status.replace("_", "-")}`}>{row.status}</span></td><td><div className="live-record-actions"><button className="data-icon-button" title="Edit" aria-label={`Edit ${name}`} onClick={() => editEntry(row)}><Pencil size={16} /></button><button className="data-icon-button live-delete-button" title="Delete" aria-label={`Delete ${name}`} onClick={() => void removeEntry(row)}><Trash2 size={16} /></button></div></td></tr>; })}</tbody></table></div></section>
    <AnimatePresence>{open && <Modal title={driverMode ? "Add driver" : "Add party"} subtitle="This record will be available in trip assignment." saving={saving} valid={Boolean(driverMode ? form.full_name : form.name)} onClose={() => setOpen(false)} onSave={() => void save()}><div className="vehicle-form-grid transport-form"><label><span>Name</span><input value={driverMode ? form.full_name : form.name} onChange={e => setForm({ ...form, [driverMode ? "full_name" : "name"]: e.target.value })} /></label><label><span>Phone</span><input value={form.phone} onChange={e => setForm({ ...form, phone: e.target.value })} /></label>{driverMode ? <><label><span>License number</span><input value={form.license_number} onChange={e => setForm({ ...form, license_number: e.target.value })} /></label><label><span>License expiry</span><input type="date" value={form.license_expiry} onChange={e => setForm({ ...form, license_expiry: e.target.value })} /></label></> : <><label><span>Contact person</span><input value={form.contact_name} onChange={e => setForm({ ...form, contact_name: e.target.value })} /></label><label><span>Email</span><input type="email" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} /></label><label><span>Credit limit</span><input type="number" value={form.credit_limit} onChange={e => setForm({ ...form, credit_limit: e.target.value })} /></label><label><span>Payment terms (days)</span><input type="number" value={form.payment_terms_days} onChange={e => setForm({ ...form, payment_terms_days: e.target.value })} /></label></>}</div></Modal>}</AnimatePresence>
  </motion.main>;
}

function exportExcel(data: Array<Record<string, string | number>>, name: string) {
  const cols = Object.keys(data[0] ?? { Message: "No records" }); const rows = data.length ? data : [{ Message: "No records" }];
  const esc = (v: unknown) => String(v ?? "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  const xml = `<?xml version="1.0"?><Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet" xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet"><Worksheet ss:Name="Fleetora"><Table><Row>${cols.map(c => `<Cell><Data ss:Type="String">${esc(c)}</Data></Cell>`).join("")}</Row>${rows.map(r => `<Row>${cols.map(c => `<Cell><Data ss:Type="String">${esc(r[c])}</Data></Cell>`).join("")}</Row>`).join("")}</Table></Worksheet></Workbook>`;
  const url = URL.createObjectURL(new Blob([xml], { type: "application/vnd.ms-excel" })); const a = document.createElement("a"); a.href = url; a.download = `${name}.xls`; a.click(); URL.revokeObjectURL(url);
}

/** Opens the browser's print dialog with a report-friendly title. This keeps PDF
 * generation client-side while scheduled PDF delivery remains server-owned. */
function printReport(name: string) {
  if (typeof window === "undefined") return;
  const previousTitle = document.title;
  document.title = name;
  window.setTimeout(() => {
    window.print();
    window.setTimeout(() => { document.title = previousTitle; }, 250);
  }, 0);
}

function ScalableReportPanels({ report, schedules, onSchedule }: { report: ScalableReport | null; schedules: ReportSchedule[]; onSchedule: () => void }) {
  const [dimension, setDimension] = useState<ProfitDimension["dimension"]>("truck");
  const rows = report?.profitability.filter(row => row.dimension === dimension) ?? [];
  const tripRows = report?.trips ?? [];
  return <><div className="filter-bar report-filter"><label><span>Profitability dimension</span><select value={dimension} onChange={event => setDimension(event.target.value as ProfitDimension["dimension"])}>{["truck","driver","customer","material","route"].map(value => <option key={value} value={value}>{value}</option>)}</select></label><button className="module-button module-button-secondary" onClick={onSchedule}><Plus size={15} /> Schedule PDF / Excel</button><button className="module-button module-button-secondary" onClick={() => printReport("Fleetora-report")}><FileText size={15} /> Print / PDF</button></div><div className="report-panels"><section className="module-data-panel"><div className="module-section-heading"><div><h2>{dimension} profitability</h2><p>Server-aggregated across the complete reporting period</p></div><button className="module-button module-button-secondary" onClick={() => exportExcel(rows.map(row => ({ Dimension: row.dimension, Name: row.label, Trips: row.trips, LoadedKm: row.distance_km, EmptyKm: row.empty_distance_km, TotalKm: row.total_distance_km, Revenue: row.revenue, Cost: row.cost, Profit: row.profit })), `${dimension}-profitability`)}>Excel</button></div><div className="data-table-wrap"><table className="data-table"><thead><tr><th>Name</th><th>Trips</th><th>Revenue</th><th>Cost</th><th>Profit</th></tr></thead><tbody>{rows.map(row => <tr key={`${row.dimension}-${row.label}`}><td><strong>{row.label}</strong></td><td>{row.trips}</td><td>{money(row.revenue)}</td><td>{money(row.cost)}</td><td className={Number(row.profit) >= 0 ? "data-money-positive" : "data-money-negative"}>{money(row.profit)}</td></tr>)}</tbody></table></div></section><section className="module-data-panel"><div className="module-section-heading"><div><h2>Outstanding ageing</h2><p>FIFO as of {report?.period.to}: payments reduce the oldest debits first</p></div></div><div className="data-table-wrap"><table className="data-table"><thead><tr><th>Customer</th><th>Oldest unpaid</th><th>0-30</th><th>31-60</th><th>61-90</th><th>90+</th><th>Total</th></tr></thead><tbody>{report?.ageing.map(row => <tr key={row.customer_id}><td><strong>{row.customer}</strong></td><td>{row.age_days} days</td><td>{money(row.bucket_0_30)}</td><td>{money(row.bucket_31_60)}</td><td>{money(row.bucket_61_90)}</td><td>{money(row.bucket_90_plus)}</td><td className="data-money-negative"><strong>{money(row.balance)}</strong></td></tr>)}</tbody></table>{!report?.ageing.length && <div className="data-empty"><Wallet size={22} /><strong>No outstanding balances</strong></div>}</div></section></div><section className="module-data-panel"><div className="module-section-heading"><div><h2>Trip-level P&amp;L</h2><p>Revenue, fuel and linked expense cost for every completed trip</p></div><button className="module-button module-button-secondary" onClick={() => exportExcel(tripRows.map(row => ({ Trip: row.trip_number ?? "", Route: `${row.origin ?? ""} - ${row.destination ?? ""}`, Material: row.material_name ?? "", WeightTonnes: Number(row.quantity_tonnes ?? 0), LoadedKm: Number(row.distance_km ?? 0), EmptyKm: Number(row.empty_distance_km ?? 0), Revenue: Number(row.freight_amount ?? 0), Cost: Number(row.cost ?? 0), Profit: Number(row.freight_amount ?? 0) - Number(row.cost ?? 0) })), "Trip-level-P-and-L")}>Excel</button></div><div className="data-table-wrap"><table className="data-table"><thead><tr><th>Trip</th><th>Route</th><th>Material / weight</th><th>Revenue</th><th>Cost</th><th>Profit</th></tr></thead><tbody>{tripRows.map(row => { const revenue = Number(row.freight_amount ?? 0); const cost = Number(row.cost ?? 0); return <tr key={String(row.id ?? row.trip_number)}><td><strong>{String(row.trip_number ?? "-")}</strong></td><td>{String(row.origin ?? "-")} - {String(row.destination ?? "-")}</td><td>{String(row.material_name ?? "-")}<small className="data-cell-note">{Number(row.quantity_tonnes ?? 0).toLocaleString("en-IN")} t</small></td><td>{money(revenue)}</td><td>{money(cost)}</td><td className={revenue - cost >= 0 ? "data-money-positive" : "data-money-negative"}>{money(revenue - cost)}</td></tr>; })}</tbody></table>{!tripRows.length && <div className="data-empty"><BarChart3 size={22} /><strong>No completed trips in this period</strong></div>}</div></section><section className="module-data-panel"><div className="module-section-heading"><div><h2>Fleet utilization and empty running</h2><p>Utilization is active completed-trip days divided by period days, capped at 100%. Empty running uses recorded deadhead kilometres.</p></div></div><div className="data-table-wrap"><table className="data-table"><thead><tr><th>Truck</th><th>Trips</th><th>Active days</th><th>Loaded km</th><th>Empty km</th><th>Empty running</th><th>Utilization</th></tr></thead><tbody>{report?.utilization.map(row => <tr key={row.id}><td><strong>{row.registration_number}</strong></td><td>{row.completed_trips}</td><td>{row.active_days} / {row.period_days}</td><td>{Number(row.loaded_km).toLocaleString("en-IN")} km</td><td>{Number(row.empty_km).toLocaleString("en-IN")} km</td><td>{Number(row.empty_running_pct).toFixed(1)}%</td><td>{Number(row.utilization_pct).toFixed(1)}%</td></tr>)}</tbody></table></div></section><section className="module-data-panel"><div className="module-section-heading"><div><h2>Scheduled deliveries</h2><p>Recurring PDF and Excel report definitions</p></div><span className="module-record-count">{schedules.length} schedules</span></div><div className="data-table-wrap"><table className="data-table"><thead><tr><th>Name</th><th>Report</th><th>Format</th><th>Frequency</th><th>Recipients</th><th>Next run</th><th>Status</th></tr></thead><tbody>{schedules.map(row => <tr key={row.id}><td><strong>{row.name}</strong></td><td>{row.report_type}</td><td>{row.format.toUpperCase()}</td><td>{row.frequency}</td><td>{row.recipients.join(", ")}</td><td>{row.next_run_at ? new Date(row.next_run_at).toLocaleString("en-IN") : "Queued by scheduler"}</td><td>{row.status}</td></tr>)}</tbody></table></div></section></>;
}

function ReportsView({ ledgerOnly = false }: { ledgerOnly?: boolean }) {
  const [resources, setResources] = useState<Resources>({ vehicles: [], drivers: [], customers: [] }); const [ledger, setLedger] = useState<LedgerEntry[]>([]); const [scalable, setScalable] = useState<ScalableReport | null>(null); const [schedules, setSchedules] = useState<ReportSchedule[]>([]); const [month, setMonth] = useState(today().slice(0, 7)); const [selectedPartyId, setSelectedPartyId] = useState(""); const [selectedReportTruckId, setSelectedReportTruckId] = useState(""); const [payment, setPayment] = useState({ customer_id: "", amount: "", payment_mode: "bank", reference: "", entry_date: today() }); const [editingPaymentId, setEditingPaymentId] = useState<string | null>(null); const [open, setOpen] = useState(false); const [scheduleOpen, setScheduleOpen] = useState(false); const [schedule, setSchedule] = useState({ name: "Monthly management report", report_type: "profitability", format: "xlsx", frequency: "monthly", recipients: "", status: "active" }); const [saving, setSaving] = useState(false); const [error, setError] = useState<string | null>(null);
  const load = useCallback(async () => { try { const end = new Date(Number(month.slice(0,4)), Number(month.slice(5,7)), 0).toISOString().slice(0,10); const [refs, ledgerRows, complete, scheduleRows] = await Promise.all([fleetoraApi<Resources>("/resources"), fleetoraApi<LedgerEntry[]>("/ledger"), fleetoraApi<ScalableReport>(`/reports/profitability?from=${month}-01&to=${end}`), fleetoraApi<ReportSchedule[]>("/report-schedules")]); setResources(refs); setLedger(ledgerRows); setScalable(complete); setSchedules(scheduleRows); setError(null); } catch (e) { setError(e instanceof Error ? e.message : "Could not load reports."); } }, [month]);
  useEffect(() => {
    const timer = window.setTimeout(() => void load(), 0);
    return () => window.clearTimeout(timer);
  }, [load]);
  const trips = scalable?.trips ?? []; const revenue = Number(scalable?.summary.revenue ?? 0); const costs = Number(scalable?.summary.cost ?? 0);
  const partyBalances = useMemo(() => resources.customers.map(c => { const rows = ledger.filter(x => x.customer_id === c.id); return { id: c.id, name: c.name, debit: rows.filter(x => x.entry_type === "debit").reduce((s, x) => s + Number(x.amount), 0), credit: rows.filter(x => x.entry_type === "credit").reduce((s, x) => s + Number(x.amount), 0) }; }).filter(x => x.debit || x.credit), [resources.customers, ledger]);
  const filteredLedger = selectedPartyId ? ledger.filter(entry => entry.customer_id === selectedPartyId) : ledger;
  const selectedParty = partyBalances.find(party => party.id === selectedPartyId);
  const truckRows = (scalable?.profitability ?? []).filter(row => row.dimension === "truck").map(row => ({ Id: row.entity_id ?? "", Truck: row.label, Trips: Number(row.trips), Weight: Number(row.weight_tonnes), Distance: Number(row.distance_km), EmptyDistance: Number(row.empty_distance_km), TotalDistance: Number(row.total_distance_km), Income: Number(row.revenue), Cost: Number(row.cost), Profit: Number(row.profit) }));
  const reportTrips = selectedReportTruckId ? trips.filter(trip => trip.vehicle_id === selectedReportTruckId) : trips;
  const driverRows = (scalable?.profitability ?? []).filter(row => row.dimension === "driver").map(row => ({ Driver: row.label, Trips: Number(row.trips), Completed: Number(row.trips), Income: Number(row.revenue) }));
  function addPayment() { setEditingPaymentId(null); setPayment({ customer_id: selectedPartyId, amount: "", payment_mode: "bank", reference: "", entry_date: today() }); setOpen(true); }
  function editPayment(entry: LedgerEntry) { setEditingPaymentId(entry.id); setPayment({ customer_id: entry.customer_id, amount: String(entry.amount), payment_mode: entry.payment_mode ?? "bank", reference: entry.reference ?? "", entry_date: entry.entry_date.slice(0, 10) }); setOpen(true); }
  async function recordPayment() { setSaving(true); try { await fleetoraApi(editingPaymentId ? `/ledger/payments/${editingPaymentId}` : "/ledger/payments", { method: editingPaymentId ? "PATCH" : "POST", body: JSON.stringify({ ...payment, amount: Number(payment.amount) }) }); setOpen(false); setEditingPaymentId(null); await load(); } catch (e) { setError(e instanceof Error ? e.message : "Could not record payment."); } finally { setSaving(false); } }
  async function removePayment(entry: LedgerEntry) { if (!window.confirm(`Delete payment of ${money(entry.amount)}? The party Udhar balance will be recalculated.`)) return; try { await fleetoraApi(`/ledger/payments/${entry.id}`, { method: "DELETE" }); await load(); } catch (e) { setError(e instanceof Error ? e.message : "Could not delete payment."); } }
  async function saveSchedule() { setSaving(true); try { await fleetoraApi("/report-schedules", { method: "POST", body: JSON.stringify({ ...schedule, recipients: schedule.recipients.split(",").map(x => x.trim()).filter(Boolean) }) }); setScheduleOpen(false); await load(); } catch (e) { setError(e instanceof Error ? e.message : "Could not schedule report."); } finally { setSaving(false); } }
  return <motion.main className="module-page" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
    <PageHeader icon={ledgerOnly ? Wallet : BarChart3} eyebrow="Finance intelligence" title={ledgerOnly ? "Party ledger and Udhar" : "Transport reports"} subtitle="Completed trip income, costs, profit, truck and driver performance from live data." action="Record payment" onAdd={addPayment} />
    {error && <div className="module-inline-error">{error}</div>}
    {!ledgerOnly && <>
      <div className="filter-bar report-filter"><label><span>Report month</span><input type="month" value={month} onChange={e => setMonth(e.target.value)} /></label><label><span>Truck detail</span><select value={selectedReportTruckId} onChange={e => setSelectedReportTruckId(e.target.value)}><option value="">All trucks</option>{truckRows.filter(vehicle => vehicle.Id).map(vehicle => <option key={vehicle.Id} value={vehicle.Id}>{vehicle.Truck}</option>)}</select></label><button className="module-button module-button-secondary" onClick={() => exportExcel([{ Month: month, Revenue: revenue, Costs: costs, Profit: revenue - costs }, ...truckRows], `Fleetora-report-${month}`)}><Download size={15} /> Export Excel</button></div>
      <section className="module-kpis">{[["Trip income", money(revenue)], ["Fuel + expenses", money(costs)], ["Net profit / loss", money(revenue - costs)], ["Completed trips", trips.filter(t => t.status === "delivered").length]].map(([label, value]) => <article className="module-kpi module-tone-emerald" key={label}><span className="module-kpi-icon"><BarChart3 size={18} /></span><div className="module-kpi-copy"><span>{label}</span><strong>{value}</strong><small>{month}</small></div></article>)}</section>
      <ScalableReportPanels report={scalable} schedules={schedules} onSchedule={() => setScheduleOpen(true)} />
      <div className="report-panels"><section className="module-data-panel"><div className="module-section-heading"><div><h2>Truck-wise performance</h2><p>Trips, loaded and empty distance, income, cost and profit</p></div><button className="module-button module-button-secondary" onClick={() => exportExcel(truckRows, `Truck-report-${month}`)}>Excel</button></div><div className="data-table-wrap"><table className="data-table"><thead><tr><th>Truck</th><th>Trips</th><th>Weight</th><th>Loaded km</th><th>Empty km</th><th>Income</th><th>Cost</th><th>Profit</th></tr></thead><tbody>{truckRows.map(r => <tr key={r.Truck}><td><strong>{r.Truck}</strong></td><td>{r.Trips}</td><td>{r.Weight.toLocaleString("en-IN")} t</td><td>{r.Distance.toLocaleString("en-IN")} km</td><td>{r.EmptyDistance.toLocaleString("en-IN")} km</td><td>{money(r.Income)}</td><td>{money(r.Cost)}</td><td className={r.Profit >= 0 ? "data-money-positive" : "data-money-negative"}>{money(r.Profit)}</td></tr>)}</tbody></table></div></section><section className="module-data-panel"><div className="module-section-heading"><div><h2>Driver-wise report</h2><p>Trips, completion and linked revenue</p></div><button className="module-button module-button-secondary" onClick={() => exportExcel(driverRows, `Driver-report-${month}`)}>Excel</button></div><div className="data-table-wrap"><table className="data-table"><thead><tr><th>Driver</th><th>Trips</th><th>Completed</th><th>Income</th></tr></thead><tbody>{driverRows.map(r => <tr key={r.Driver}><td>{r.Driver}</td><td>{r.Trips}</td><td>{r.Completed}</td><td>{money(r.Income)}</td></tr>)}</tbody></table></div></section></div>
      <section className="module-data-panel"><div className="module-section-heading"><div><h2>{selectedReportTruckId ? `${truckRows.find(vehicle => vehicle.Id === selectedReportTruckId)?.Truck ?? "Truck"} trip report` : "All truck trip details"}</h2><p>Material, weight, loaded distance and empty running for every trip</p></div><span className="module-record-count">{reportTrips.length} trips</span></div><div className="data-table-wrap"><table className="data-table"><thead><tr><th>Date</th><th>Truck</th><th>Trip</th><th>Party</th><th>Material</th><th>Weight</th><th>Route</th><th>Loaded / empty km</th><th>Income</th><th>Status</th></tr></thead><tbody>{reportTrips.map(trip => <tr key={trip.id}><td>{trip.scheduled_start_at ? new Date(trip.scheduled_start_at).toLocaleDateString("en-IN") : "-"}</td><td>{trip.vehicle_registration ?? "-"}</td><td><strong>{trip.trip_number}</strong></td><td>{trip.customer_name ?? "-"}</td><td>{trip.material_name ?? "-"}</td><td>{Number(trip.quantity_tonnes).toLocaleString("en-IN")} t</td><td>{trip.origin} - {trip.destination}</td><td>{Number(trip.distance_km ?? 0).toLocaleString("en-IN")} / {Number(trip.empty_distance_km ?? 0).toLocaleString("en-IN")} km</td><td>{money(trip.freight_amount)}</td><td>{tripStatus[trip.status] ?? trip.status}</td></tr>)}</tbody></table>{!reportTrips.length && <div className="data-empty"><Truck size={22} /><strong>No trips for this truck and month</strong></div>}</div></section>
    </>}
    <section className="module-data-panel">
      <div className="module-section-heading"><div><h2>Party ledger / Udhar report</h2><p>Choose View ledger to open a separate statement for that party.</p></div><button className="module-button module-button-secondary" onClick={() => exportExcel(partyBalances.map(x => ({ Party: x.name, TripAmount: x.debit, Received: x.credit, Udhar: x.debit - x.credit })), "Party-ledger-summary")}>Export summary</button></div>
      <div className="data-table-wrap"><table className="data-table"><thead><tr><th>Party</th><th>Completed trip amount</th><th>Payments received</th><th>Udhar balance</th><th>Statement</th></tr></thead><tbody>{partyBalances.map(x => <tr key={x.id}><td><strong>{x.name}</strong></td><td>{money(x.debit)}</td><td>{money(x.credit)}</td><td className={x.debit - x.credit > 0 ? "data-money-negative" : "data-money-positive"}><strong>{money(x.debit - x.credit)}</strong></td><td><button className="module-button module-button-secondary" onClick={() => setSelectedPartyId(x.id)}>View ledger</button></td></tr>)}</tbody></table>{!partyBalances.length && <div className="data-empty"><Wallet size={22} /><strong>No ledger entries</strong><span>Complete a trip to create the party debit automatically.</span></div>}</div>
    </section>
    <div className="filter-bar report-filter party-ledger-filter"><label><span>Party statement</span><select value={selectedPartyId} onChange={event => setSelectedPartyId(event.target.value)}><option value="">All parties</option>{partyBalances.map(party => <option key={party.id} value={party.id}>{party.name}</option>)}</select></label>{selectedParty && <div className="party-ledger-balance"><span>Current Udhar</span><strong className={selectedParty.debit - selectedParty.credit > 0 ? "data-money-negative" : "data-money-positive"}>{money(selectedParty.debit - selectedParty.credit)}</strong></div>}</div>
    <section className="module-data-panel"><div className="module-section-heading"><div><h2>{selectedParty ? `${selectedParty.name} ledger statement` : "All party ledger transactions"}</h2><p>Trip material, weight, debits and received payments with recorded dates</p></div><div className="module-section-actions"><span className="module-record-count">{filteredLedger.length} entries</span><button className="module-button module-button-secondary" onClick={() => exportExcel(filteredLedger.map(entry => ({ Date: entry.entry_date, Party: entry.customers?.name ?? "", Reference: entry.reference ?? entry.trips?.trip_number ?? "", Material: entry.trips?.material_name ?? "", WeightTonnes: entry.trips?.quantity_tonnes ?? 0, Debit: entry.entry_type === "debit" ? entry.amount : 0, Payment: entry.entry_type === "credit" ? entry.amount : 0, Mode: entry.payment_mode ?? "" })), selectedParty ? `${selectedParty.name}-ledger` : "All-party-ledger")}>Export statement</button></div></div><div className="data-table-wrap"><table className="data-table"><thead><tr><th>Date</th><th>Party</th><th>Reference / Trip</th><th>Material</th><th>Weight</th><th>Debit</th><th>Payment received</th><th>Mode</th><th>Actions</th></tr></thead><tbody>{filteredLedger.map(entry => <tr key={entry.id}><td>{new Date(entry.entry_date).toLocaleDateString("en-IN")}</td><td><strong>{entry.customers?.name ?? "-"}</strong></td><td>{entry.reference ?? entry.trips?.trip_number ?? "-"}</td><td>{entry.trips?.material_name ?? (entry.entry_type === "credit" ? "Payment" : "-")}</td><td>{entry.trips && Number(entry.trips.quantity_tonnes) > 0 ? `${Number(entry.trips.quantity_tonnes).toLocaleString("en-IN")} t` : "-"}</td><td>{entry.entry_type === "debit" ? money(entry.amount) : "-"}</td><td className="data-money-positive">{entry.entry_type === "credit" ? money(entry.amount) : "-"}</td><td>{entry.payment_mode ?? "-"}</td><td>{entry.entry_type === "credit" ? <div className="live-record-actions"><button className="data-icon-button" title="Edit payment" aria-label="Edit payment" onClick={() => editPayment(entry)}><Pencil size={16} /></button><button className="data-icon-button live-delete-button" title="Delete payment" aria-label="Delete payment" onClick={() => void removePayment(entry)}><Trash2 size={16} /></button></div> : <span className="module-record-count">From trip</span>}</td></tr>)}</tbody></table>{!filteredLedger.length && <div className="data-empty"><Wallet size={22} /><strong>No ledger transactions for this party</strong></div>}</div></section>
    <AnimatePresence>{open && <Modal title="Record party payment" subtitle="This credit reduces the party's Udhar balance." saving={saving} valid={Boolean(payment.customer_id && payment.amount && payment.entry_date)} onClose={() => setOpen(false)} onSave={() => void recordPayment()}><div className="vehicle-form-grid transport-form"><label><span>Party</span><select value={payment.customer_id} onChange={e => setPayment({ ...payment, customer_id: e.target.value })}><option value="">Select party</option>{resources.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}</select></label><label><span>Amount received</span><input type="number" min="0" value={payment.amount} onChange={e => setPayment({ ...payment, amount: e.target.value })} /></label><label><span>Payment mode</span><select value={payment.payment_mode} onChange={e => setPayment({ ...payment, payment_mode: e.target.value })}><option value="cash">Cash</option><option value="bank">Bank</option></select></label><label><span>Payment date</span><input type="date" value={payment.entry_date} onChange={e => setPayment({ ...payment, entry_date: e.target.value })} /></label><label className="vehicle-form-wide"><span>Reference</span><input value={payment.reference} onChange={e => setPayment({ ...payment, reference: e.target.value })} /></label></div></Modal>}{scheduleOpen && <Modal title="Schedule report delivery" subtitle="Create a recurring PDF or Excel report definition." saving={saving} valid={Boolean(schedule.name && schedule.recipients)} onClose={() => setScheduleOpen(false)} onSave={() => void saveSchedule()}><div className="vehicle-form-grid"><label><span>Schedule name</span><input value={schedule.name} onChange={e => setSchedule({ ...schedule, name: e.target.value })} /></label><label><span>Report</span><select value={schedule.report_type} onChange={e => setSchedule({ ...schedule, report_type: e.target.value })}>{["profitability","trip_pnl","ageing","utilization","maintenance"].map(x => <option key={x}>{x}</option>)}</select></label><label><span>Format</span><select value={schedule.format} onChange={e => setSchedule({ ...schedule, format: e.target.value })}><option value="xlsx">Excel</option><option value="pdf">PDF</option></select></label><label><span>Frequency</span><select value={schedule.frequency} onChange={e => setSchedule({ ...schedule, frequency: e.target.value })}>{["daily","weekly","monthly"].map(x => <option key={x}>{x}</option>)}</select></label><label className="vehicle-form-wide"><span>Email recipients (comma separated)</span><input value={schedule.recipients} onChange={e => setSchedule({ ...schedule, recipients: e.target.value })} /></label></div></Modal>}</AnimatePresence>
  </motion.main>;
}

export function TransportAccountingView({ route }: { route: string }) {
  const moduleKey = route.toLowerCase().split("/")[0];
  if (moduleKey === "trips") return <TripView />;
  if (moduleKey === "fuel") return <CostView kind="fuel" />;
  if (moduleKey === "expenses") return <CostView kind="expenses" />;
  if (moduleKey === "reports") return <ReportsView />;
  if (moduleKey === "accounting") return <ReportsView ledgerOnly />;
  if (moduleKey === "drivers" || moduleKey === "customers") return <DirectoryView kind={moduleKey} />;
  return null;
}

export const transportAccountingRoutes = new Set(["trips", "fuel", "expenses", "reports", "accounting", "drivers", "customers"]);
